import React from "react";

export type AiRobotWomanIconProps = {
  size?: number | string;
  className?: string;
  title?: string;
  alt?: string;
};

export default function AiRobotWomanIcon({
  size = 48,
  className = "",
  title = "ai-robot-woman",
  alt = "ai-robot-woman",
}: AiRobotWomanIconProps) {
  return (
    <img
      src="data:image/svg+xml;base64,"
      width={size}
      height={size}
      className={className}
      title={title}
      alt={alt}
      style={{
        width: size,
        height: size,
        objectFit: "contain",
      }}
      loading="lazy"
      decoding="async"
    />
  );
}
